  }

  @media (prefers-color-scheme: dark) {
    :root {
      --color-background-primary: #1a1a18;
      --color-background-secondary: #242420;
      --color-background-tertiary: #2c2c2a;
      --color-background-danger: #2d1414;
      --color-background-success: #0a2018;
      --color-background-warning: #2a1e08;
      --color-background-info: #0a1e30;
      --color-text-primary: #e8e6dc;
      --color-text-secondary: #9c9a92;
      --color-text-tertiary: #6b6966;
      --color-text-danger: #f09595;
      --color-text-success: #5dcaa5;
      --color-text-warning: #fac775;
      --color-text-info: #85b7eb;
      --color-border-tertiary: rgba(255,255,255,0.10);
      --color-border-secondary: rgba(255,255,255,0.18);
    }
  }

  body {
    font-family: var(--font-sans);
    background: var(--color-background-primary);
    color: var(--color-text-primary);
    padding: 2rem 1.5rem;
    max-width: 780px;
    margin: 0 auto;
    line-height: 1.7;
  }

  h1 {
    font-size: 20px;
    font-weight: 500;
    margin-bottom: 4px;
    color: var(--color-text-primary);
  }
  .subtitle {
    font-size: 13px;
    color: var(--color-text-secondary);
    margin-bottom: 2rem;
  }

  .guide-wrap { font-size: 14px; }
  .tab-bar { display: flex; gap: 4px; border-bottom: 0.5px solid var(--color-border-tertiary); margin-bottom: 1.5rem; flex-wrap: wrap; }
  .tab-btn { padding: 8px 14px; font-size: 13px; background: none; border: none; border-bottom: 2px solid transparent; color: var(--color-text-secondary); cursor: pointer; transition: all .2s; font-family: var(--font-sans); }
  .tab-btn.active { color: var(--color-text-primary); border-bottom-color: var(--color-text-primary); font-weight: 500; }
  .tab-btn:hover:not(.active) { color: var(--color-text-primary); }
  .panel { display: none; }
  .panel.active { display: block; }

  .principle-card { background: var(--color-background-secondary); border-radius: var(--border-radius-lg); padding: 1rem 1.25rem; margin-bottom: 1rem; border-left: 2px solid; }
  .p-stable { border-color: #1D9E75; }
  .p-dynamic { border-color: #7F77DD; }
  .p-defer { border-color: #EF9F27; }
  .p-monitor { border-color: #E24B4A; }
  .card-label { font-size: 11px; font-weight: 500; letter-spacing: .05em; text-transform: uppercase; color: var(--color-text-tertiary); margin-bottom: 4px; }
  .card-title { font-size: 15px; font-weight: 500; color: var(--color-text-primary); margin-bottom: 6px; }
  .card-body { font-size: 13px; color: var(--color-text-secondary); }

  .code-block { background: var(--color-background-tertiary); border: 0.5px solid var(--color-border-tertiary); border-radius: var(--border-radius-md); padding: 12px 14px; font-family: var(--font-mono); font-size: 12px; line-height: 1.6; margin: 8px 0; overflow-x: auto; white-space: pre; }
  .code-bad { border-left: 2px solid #E24B4A; }
  .code-good { border-left: 2px solid #1D9E75; }
  .badge { display: inline-block; font-size: 11px; font-weight: 500; padding: 2px 8px; border-radius: 4px; margin-right: 4px; }
  .badge-bad { background: var(--color-background-danger); color: var(--color-text-danger); }
  .badge-good { background: var(--color-background-success); color: var(--color-text-success); }
  .badge-tip { background: var(--color-background-info); color: var(--color-text-info); }
  .badge-warn { background: var(--color-background-warning); color: var(--color-text-warning); }

  .layer-row { display: flex; align-items: center; gap: 10px; padding: 10px 12px; border-radius: var(--border-radius-md); margin-bottom: 6px; border: 0.5px solid var(--color-border-tertiary); background: var(--color-background-secondary); }
  .layer-num { font-size: 11px; font-weight: 500; width: 20px; height: 20px; border-radius: 50%; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
  .layer-name { font-weight: 500; font-size: 13px; flex: 1; }
  .layer-desc { font-size: 12px; color: var(--color-text-secondary); }
  .layer-mutability { font-size: 11px; padding: 2px 7px; border-radius: 4px; font-weight: 500; flex-shrink: 0; }
  .mut-frozen { background: #E1F5EE; color: #0F6E56; }
  .mut-append { background: #EEEDFE; color: #3C3489; }
  .mut-free { background: #F1EFE8; color: #5F5E5A; }

  .checklist-item { display: flex; align-items: flex-start; gap: 10px; padding: 8px 0; border-bottom: 0.5px solid var(--color-border-tertiary); }
  .checklist-item:last-child { border-bottom: none; }
  .check-icon { width: 18px; height: 18px; border-radius: 50%; flex-shrink: 0; margin-top: 2px; display: flex; align-items: center; justify-content: center; font-size: 10px; }
  .check-ok { background: #E1F5EE; color: #0F6E56; }
  .check-warn { background: #FAEEDA; color: #854F0B; }
  .check-fail { background: #FCEBEB; color: #A32D2D; }
  .check-label { font-size: 13px; font-weight: 500; color: var(--color-text-primary); }
  .check-sub { font-size: 12px; color: var(--color-text-secondary); }

  .kv-row { display: flex; justify-content: space-between; align-items: center; padding: 6px 0; border-bottom: 0.5px solid var(--color-border-tertiary); font-size: 13px; }
  .kv-row:last-child { border-bottom: none; }
  .kv-key { color: var(--color-text-secondary); }
  .kv-val { font-weight: 500; color: var(--color-text-primary); }

  .section-title { font-size: 13px; font-weight: 500; color: var(--color-text-tertiary); text-transform: uppercase; letter-spacing: .05em; margin: 1.5rem 0 .75rem; }

  .sim-wrap { border: 0.5px solid var(--color-border-tertiary); border-radius: var(--border-radius-lg); overflow: hidden; }
  .sim-header { background: var(--color-background-secondary); padding: 10px 14px; font-size: 12px; color: var(--color-text-secondary); display: flex; gap: 12px; align-items: center; flex-wrap: wrap; }
  .sim-body { padding: 14px; }

  .toggle-wrap { display: flex; gap: 6px; margin-bottom: 1rem; flex-wrap: wrap; }
  .toggle-opt { padding: 5px 12px; font-size: 12px; border: 0.5px solid var(--color-border-tertiary); border-radius: 20px; cursor: pointer; background: none; font-family: var(--font-sans); color: var(--color-text-secondary); transition: all .15s; }
  .toggle-opt.sel { background: var(--color-text-primary); color: var(--color-background-primary); border-color: var(--color-text-primary); }

  input[type=range] { width: 100%; accent-color: var(--color-text-primary); }
</style>
</head>
<body>
<h1>Claude Cache 설계 가이드</h1>
<p class="subtitle">CSP 워크플로우 적용 — Ouroboros · ESCON · HR Agent 최적화</p>

<div class="guide-wrap">
<div class="tab-bar">
  <button class="tab-btn active" onclick="showTab('why')">개념 이해</button>
  <button class="tab-btn" onclick="showTab('arch')">레이어 설계</button>
  <button class="tab-btn" onclick="showTab('patterns')">4가지 패턴</button>
  <button class="tab-btn" onclick="showTab('apply')">CSP 적용 체크</button>
  <button class="tab-btn" onclick="showTab('sim')">비용 시뮬레이터</button>
</div>

<!-- TAB 1 -->
<div id="tab-why" class="panel active">
  <div class="principle-card p-stable">
    <div class="card-label">핵심 원리</div>
    <div class="card-title">캐시는 앞에서부터 토큰 단위로 매칭된다</div>
    <div class="card-body">Anthropic API의 프롬프트 캐싱은 <strong>접두사(prefix) 매칭</strong>입니다. 처음 토큰부터 순서대로 비교해서, 한 글자라도 달라지면 그 이후 모든 것이 캐시 미스가 됩니다. 건너뛰거나 부분 매칭하는 방법은 없습니다.</div>
  </div>

  <div class="section-title">캐시 히트 vs 미스 — 비용 차이</div>
  <div class="sim-wrap">
    <div class="sim-header">
      <span>캐시된 토큰 비용</span><strong style="color:#1D9E75">일반의 10%</strong>
      <span style="margin-left:12px">캐시 미스 시</span><strong style="color:#E24B4A">10배 비용 폭증</strong>
    </div>
    <div class="sim-body">
      <div class="kv-row"><span class="kv-key">시스템 프롬프트 (CLAUDE.md 포함)</span><span class="kv-val">~50,000 토큰</span></div>
      <div class="kv-row"><span class="kv-key">캐시 히트 시 비용</span><span class="kv-val" style="color:#1D9E75">50,000 × 10% = 5,000 토큰 과금</span></div>
      <div class="kv-row"><span class="kv-key">캐시 미스 시 비용</span><span class="kv-val" style="color:#E24B4A">50,000 × 100% = 50,000 토큰 과금</span></div>
      <div class="kv-row"><span class="kv-key">시스템 프롬프트에 타임스탬프 1개 추가 시</span><span class="kv-val" style="color:#E24B4A">매 요청마다 전액 과금</span></div>
    </div>
  </div>

  <div class="section-title">캐시가 깨지는 3가지 원인</div>
  <div class="checklist-item">
    <div class="check-icon check-fail">✕</div>
    <div>
      <div class="check-label">동적 값이 시스템 프롬프트에 들어갈 때</div>
      <div class="check-sub">타임스탬프, 현재 날짜, 세션 ID, DoD 상태값 등이 매 요청마다 바뀌면 첫 토큰부터 미스</div>
    </div>
  </div>
  <div class="checklist-item">
    <div class="check-icon check-fail">✕</div>
    <div>
      <div class="check-label">도구 정의의 순서가 바뀔 때</div>
      <div class="check-sub">도구 내용은 같아도 직렬화 순서만 바뀌면 그 지점에서 캐시 끊김</div>
    </div>
  </div>
  <div class="checklist-item">
    <div class="check-icon check-fail">✕</div>
    <div>
      <div class="check-label">세션 중 시스템 프롬프트를 직접 수정할 때</div>
      <div class="check-sub">모드 전환, 컨텍스트 업데이트를 system_prompt 편집으로 구현하면 접두사 전체 무효화</div>
    </div>
  </div>
</div>

<!-- TAB 2 -->
<div id="tab-arch" class="panel">
  <div class="section-title">Claude Code 팀의 프롬프트 레이어 순서 (검증된 설계)</div>

  <div class="layer-row">
    <div class="layer-num" style="background:#E1F5EE;color:#085041">1</div>
    <div style="flex:1">
      <div class="layer-name">정적 시스템 프롬프트</div>
      <div class="layer-desc">절대 바뀌지 않는 페르소나, 핵심 지시사항</div>
    </div>
    <span class="layer-mutability mut-frozen">불변</span>
  </div>
  <div class="layer-row">
    <div class="layer-num" style="background:#E1F5EE;color:#085041">2</div>
    <div style="flex:1">
      <div class="layer-name">CLAUDE.md (Rules / Skills 선언)</div>
      <div class="layer-desc">아키텍처 원칙, 도구 정의 — 세션 상태 포함 금지</div>
    </div>
    <span class="layer-mutability mut-frozen">불변</span>
  </div>
  <div class="layer-row">
    <div class="layer-num" style="background:#EEEDFE;color:#3C3489">3</div>
    <div style="flex:1">
      <div class="layer-name">도구 스텁 (defer_loading)</div>
      <div class="layer-desc">전체 스키마 대신 이름 + 플래그만 — 순서 고정</div>
    </div>
    <span class="layer-mutability mut-frozen">불변</span>
  </div>
  <div class="layer-row">
    <div class="layer-num" style="background:#FAEEDA;color:#633806">4</div>
    <div style="flex:1">
      <div class="layer-name">세션 컨텍스트 (system-reminder)</div>
      <div class="layer-desc">DoD 상태, Convergence Score, 현재 Phase — user turn에 태그로 주입</div>
    </div>
    <span class="layer-mutability mut-append">user turn 주입</span>
  </div>
  <div class="layer-row">
    <div class="layer-num" style="background:#F1EFE8;color:#444441">5</div>
    <div style="flex:1">
      <div class="layer-name">대화 메시지</div>
      <div class="layer-desc">매 턴마다 바뀌는 실제 요청 — 항상 맨 뒤</div>
    </div>
    <span class="layer-mutability mut-free">자유</span>
  </div>

  <div class="section-title">CSP 4-레이어 폴더와 매핑</div>
  <div class="sim-wrap">
    <div class="sim-body">
      <div class="kv-row"><span class="kv-key">Rules/</span><span class="kv-val" style="font-size:12px">→ 레이어 1 (불변 시스템 원칙)</span></div>
      <div class="kv-row"><span class="kv-key">Skills/</span><span class="kv-val" style="font-size:12px">→ 레이어 2 (불변 능력 선언)</span></div>
      <div class="kv-row"><span class="kv-key">Agents/</span><span class="kv-val" style="font-size:12px">→ 레이어 3 (스텁으로 등록, 온디맨드 로딩)</span></div>
      <div class="kv-row"><span class="kv-key">CLAUDE.md</span><span class="kv-val" style="font-size:12px">→ 레이어 1+2 조합 — DoD 상태값 절대 미포함</span></div>
      <div class="kv-row"><span class="kv-key">Ouroboros 상태값</span><span class="kv-val" style="font-size:12px">→ 레이어 4 (system-reminder 태그로 user turn 주입)</span></div>
    </div>
  </div>
</div>

<!-- TAB 3 -->
<div id="tab-patterns" class="panel">
  <div class="toggle-wrap">
    <button class="toggle-opt sel" onclick="showPattern('p1',this)">패턴 1: system-reminder</button>
    <button class="toggle-opt" onclick="showPattern('p2',this)">패턴 2: defer_loading</button>
    <button class="toggle-opt" onclick="showPattern('p3',this)">패턴 3: 컨텍스트 압축</button>
    <button class="toggle-opt" onclick="showPattern('p4',this)">패턴 4: 모드 전환</button>
  </div>

  <div id="pat-p1" class="pat-panel">
    <div class="principle-card p-dynamic">
      <div class="card-label">패턴 1 — Ouroboros DoD 상태 주입</div>
      <div class="card-title">시스템 프롬프트를 수정하지 말고, user turn에 태그로 주입하라</div>
      <div class="card-body">Convergence Score, 현재 Phase, DoD 체크포인트 상태를 CLAUDE.md에 쓰거나 system_prompt를 수정하지 않는다. 매 사이클마다 user message 앞에 &lt;system-reminder&gt; 블록으로 주입한다.</div>
    </div>
    <span class="badge badge-bad">❌ 캐시 깨짐</span>
    <div class="code-block code-bad">system_prompt = f"""
{base_instructions}
현재 DoD 상태: {current_dod_state}   ← 매번 바뀜
Convergence Score: {score}            ← 매번 바뀜
현재 Phase: {phase}                   ← 매번 바뀜
"""</div>
    <span class="badge badge-good">✅ 캐시 보존</span>
    <div class="code-block code-good">system_prompt = base_instructions  # 절대 불변

user_message = f"""
&lt;system-reminder&gt;
현재 DoD 상태: {current_dod_state}
Convergence Score: {score}
현재 Phase: {phase}
PathologyDetector: {pathology_status}
&lt;/system-reminder&gt;

{actual_request}
"""</div>
  </div>

  <div id="pat-p2" class="pat-panel" style="display:none">
    <div class="principle-card p-defer">
      <div class="card-label">패턴 2 — ESCON 도구 지연 로딩</div>
      <div class="card-title">도구를 빼지 말고 스텁으로 등록하라</div>
      <div class="card-body">Skill Ontology 탐색 함수들(get_adjacent_skills, traverse_path 등)을 처음부터 전부 로딩하지 않는다. 이름과 defer_loading 플래그만 있는 스텁을 고정 순서로 등록하고, 필요할 때 ToolSearch로 실제 스키마를 로딩한다.</div>
    </div>
    <span class="badge badge-bad">❌ 캐시 깨짐 (도구 제거/추가 시)</span>
    <div class="code-block code-bad">tools = []
if context_needs_skill_graph:
    tools.append(get_adjacent_skills_full_schema)  # 조건부 추가/제거
if context_needs_temporal:
    tools.append(temporal_traverse_full_schema)     # → 순서 비결정적</div>
    <span class="badge badge-good">✅ 캐시 보존</span>
    <div class="code-block code-good">tools = [  # 항상 동일한 순서로 고정
    {"name": "get_adjacent_skills", "defer_loading": True},
    {"name": "traverse_path",       "defer_loading": True},
    {"name": "query_level_dist",    "defer_loading": True},
    {"name": "temporal_traverse",   "defer_loading": True},
    {"name": "ToolSearch"},  # 실제 스키마 온디맨드 로딩
]</div>
  </div>

  <div id="pat-p3" class="pat-panel" style="display:none">
    <div class="principle-card p-stable">
      <div class="card-label">패턴 3 — Pulse Check / 리더십 평가 Agent 압축</div>
      <div class="card-title">압축 호출도 부모와 동일한 시스템 프롬프트를 써라</div>
      <div class="card-body">장시간 실행되는 HR 자동화 Agent가 컨텍스트 윈도우를 가득 채우면 압축이 필요하다. 이때 압축 전용 시스템 프롬프트를 새로 만들면, 가장 비싼 순간(최대 컨텍스트)에 캐시 미스가 발생한다.</div>
    </div>
    <span class="badge badge-bad">❌ 최악의 타이밍에 캐시 미스</span>
    <div class="code-block code-bad">compression_call = {
    "system": "당신은 대화 요약 전문가입니다...",  # 새 프롬프트
    "tools": compression_tools,                      # 다른 도구 세트
    "messages": full_history                         # 최대 컨텍스트
}</div>
    <span class="badge badge-good">✅ 압축도 캐시 히트</span>
    <div class="code-block code-good">compression_call = {
    "system": base_system_prompt,   # 부모와 동일한 프롬프트
    "tools": base_tools,            # 부모와 동일한 도구 세트
    "messages": [
