function updateSim() {
  const reqs = parseInt(document.getElementById('req-slider').value);
  const ctx = parseInt(document.getElementById('ctx-slider').value);
  document.getElementById('req-val').textContent = reqs + '회';
  document.getElementById('ctx-val').textContent = ctx.toLocaleString() + ' 토큰';
  const hitCost = Math.round(reqs * ctx * 0.10);
  const missCost = Math.round(reqs * ctx * 1.00);
  const saved = missCost - hitCost;
  const ratio = Math.round(missCost / hitCost);
  document.getElementById('cost-good').textContent = hitCost.toLocaleString();
  document.getElementById('cost-bad').textContent = missCost.toLocaleString();
  document.getElementById('sim-insight').innerHTML =
